     1→import { app, BrowserWindow, ipcMain, Tray, Menu, nativeImage, systemPreferences, dialog } from 'electron';
     2→import { join } from 'path';
     3→import { settingsManager, TranscriptionMode } from '../config/settings';
     4→import { windowManager } from './windowManager';
     5→import { globalShortcutManager } from './globalShortcuts';
     6→// import { audioCapture } from './audioCapture'; // Removed
     7→import { streamingTranscription } from './streamingTranscription';
     8→import { textPostProcessor } from './textPostProcessor';
     9→import { textInjection } from './textInjection';
    10→
    11→let tray: Tray | null = null;
    12→let settingsWindow: BrowserWindow | null = null;
    13→
    14→// Accumulated transcript across speech turns
    15→let currentTranscript = '';
    16→let isStreamingActive = false;
    17→
    18→// Tray pulse animation
    19→let trayPulseInterval: NodeJS.Timeout | null = null;
    20→let trayPulseState = false;
    21→
    22→// ─── Tray Icons ───────────────────────────────────────────
    23→
    24→function createTrayIcon(color: 'default' | 'recording' | 'processing') {
    25→    // 22x22 px template images for macOS menu bar
    26→    const size = 22;
    27→    const canvas = Buffer.alloc(size * size * 4); // RGBA
    28→
    29→    const colors: Record<string, [number, number, number, number]> = {
    30→        default: [180, 180, 180, 200],     // subtle gray
    31→        recording: [0, 220, 255, 255],     // cyan pulse
    32→        processing: [255, 200, 50, 255],   // amber
    33→    };
    34→
    35→    const [r, g, b, a] = colors[color];
    36→
    37→    // Draw a simple filled circle (center dot)
    38→    const cx = size / 2;
    39→    const cy = size / 2;
    40→    const radius = color === 'default' ? 4 : 5;
    41→
    42→    for (let y = 0; y < size; y++) {
    43→        for (let x = 0; x < size; x++) {
    44→            const dist = Math.sqrt((x - cx) ** 2 + (y - cy) ** 2);
    45→            if (dist <= radius) {
    46→                const idx = (y * size + x) * 4;
    47→                canvas[idx] = r;
    48→                canvas[idx + 1] = g;
    49→                canvas[idx + 2] = b;
    50→                canvas[idx + 3] = a;
    51→            }
    52→        }
    53→    }
    54→
    55→    return nativeImage.createFromBuffer(canvas, { width: size, height: size });
    56→}
    57→
    58→function startTrayPulse() {
    59→    if (trayPulseInterval) return;
    60→    trayPulseState = false;
    61→
    62→    trayPulseInterval = setInterval(() => {
    63→        trayPulseState = !trayPulseState;
    64→        if (tray) {
    65→            tray.setImage(createTrayIcon(trayPulseState ? 'recording' : 'default'));
    66→        }
    67→    }, 500);
    68→
    69→    // Immediate first pulse
    70→    if (tray) tray.setImage(createTrayIcon('recording'));
    71→}
    72→
    73→function stopTrayPulse(processing = false) {
    74→    if (trayPulseInterval) {
    75→        clearInterval(trayPulseInterval);
    76→        trayPulseInterval = null;
    77→    }
    78→    if (tray) {
    79→        tray.setImage(createTrayIcon(processing ? 'processing' : 'default'));
    80→    }
    81→}
    82→
    83→// ─── Initialization ───────────────────────────────────────
    84→
    85→async function initialize() {
    86→    settingsManager.initializeFromEnv();
    87→
    88→    if (!settingsManager.hasApiKey()) {
    89→        console.log('No API key configured. User will need to set it in settings.');
    90→    }
    91→
    92→    // Request Accessibility permission on macOS (required for uiohook-napi global shortcuts)
    93→    if (process.platform === 'darwin') {
    94→        const trusted = systemPreferences.isTrustedAccessibilityClient(false);
    95→        if (!trusted) {
    96→            console.warn('[Main] Accessibility permission not granted. Requesting...');
    97→            systemPreferences.isTrustedAccessibilityClient(true); // triggers macOS prompt
    98→            dialog.showMessageBoxSync({
    99→                type: 'warning',
   100→                title: 'Accessibility Permission Required',
   101→                message: 'SPEECHY needs Accessibility access to detect your keyboard shortcut.',
   102→                detail: 'Please go to System Settings → Privacy & Security → Accessibility and enable SPEECHY (or Electron), then restart the app.',
   103→                buttons: ['OK'],
   104→            });
   105→        }
   106→    }
   107→
   108→    // Create overlay window (still needed for non-stealth mode)
   109→    await windowManager.createOverlayWindow();
   110→
   111→    // Wire keyboard shortcuts → recording functions
   112→    globalShortcutManager.setCallbacks(
   113→        () => startStreamingSession(),
   114→        () => stopStreamingSession(),
   115→    );
   116→    globalShortcutManager.register();
   117→
   118→    setupIPCHandlers();
   119→    setupStreamingHandlers();
   120→    createSystemTray();
   121→}
   122→
   123→// ─── Streaming Event Handlers ─────────────────────────────
   124→
   125→function setupStreamingHandlers() {
   126→    const isStealth = () => settingsManager.getSetting('stealthMode');
   127→
   128→    // Incremental transcript delta → send to UI if overlay visible
   129→    streamingTranscription.on('delta', (data: { text: string; itemId: string }) => {
   130→        if (!isStealth()) {
   131→            windowManager.sendToRenderer('transcript-delta', {
   132→                text: data.text,
   133→                itemId: data.itemId,
   134→            });
   135→        }
   136→    });
   137→
   138→    // Completed transcript for a speech turn
   139→    streamingTranscription.on('completed', (data: { text: string; itemId: string }) => {
   140→        console.log('[Main] Turn completed:', data.text);
   141→        currentTranscript += (currentTranscript ? ' ' : '') + data.text;
   142→
   143→        if (!isStealth()) {
   144→            windowManager.sendToRenderer('transcript-completed', {
   145→                text: data.text,
   146→                fullText: currentTranscript,
   147→                itemId: data.itemId,
   148→            });
   149→        }
   150→    });
   151→
   152→    streamingTranscription.on('speech_started', () => {
   153→        if (!isStealth()) {
   154→            windowManager.sendToRenderer('recording-state', { state: 'listening' });
   155→        }
   156→    });
   157→
   158→    streamingTranscription.on('speech_stopped', () => {
   159→        if (!isStealth()) {
   160→            windowManager.sendToRenderer('recording-state', { state: 'processing' });
   161→        }
   162→    });
   163→
   164→    streamingTranscription.on('connected', () => {
   165→        console.log('[Main] Streaming connected');
   166→    });
   167→
   168→    streamingTranscription.on('error', (data: { message: string }) => {
   169→        console.error('[Main] Streaming error:', data.message);
   170→        stopTrayPulse();
   171→        if (!isStealth()) {
   172→            windowManager.sendToRenderer('recording-error', { message: data.message });
   173→        }
   174→    });
   175→
   176→    // Audio capture is now handled via IPC from Renderer
   177→}
   178→
   179→// ─── Recording Session Control ────────────────────────────
   180→
   181→async function startStreamingSession() {
   182→    const apiKey = settingsManager.getSetting('apiKey');
   183→    const language = settingsManager.getSetting('language');
   184→    const stealth = settingsManager.getSetting('stealthMode');
   185→
   186→    if (!apiKey) {
   187→        if (!stealth) {
   188→            windowManager.sendToRenderer('recording-error', {
   189→                message: 'No API key configured.',
   190→            });
   191→        }
   192→        return;
   193→    }
   194→
   195→    currentTranscript = '';
   196→    isStreamingActive = true;
   197→
   198→    // Start tray pulse (always, even with overlay)
   199→    startTrayPulse();
   200→
   201→    // Show overlay only if not stealth
   202→    if (!stealth) {
   203→        windowManager.show();
   204→        windowManager.sendToRenderer('recording-state', { state: 'listening' });
   205→    }
   206→
   207→    // Connect WebSocket
   208→    streamingTranscription.connect(apiKey, language);
   209→
   210→    // Start audio capture in Renderer
   211→    windowManager.sendToRenderer('start-capture');
   212→    console.log('[Main] Session started (stealth:', stealth, ')');
   213→}
   214→
   215→async function stopStreamingSession() {
   216→    isStreamingActive = false;
   217→    const stealth = settingsManager.getSetting('stealthMode');
   218→    const mode = settingsManager.getSetting('transcriptionMode') as TranscriptionMode;
   219→
   220→    // Stop audio capture in Renderer
   221→    windowManager.sendToRenderer('stop-capture');
   222→
   223→    // Switch tray to processing
   224→    stopTrayPulse(true);
   225→
   226→    if (!stealth) {
   227→        windowManager.sendToRenderer('recording-state', { state: 'processing' });
   228→    }
   229→
   230→    // Commit audio buffer so OpenAI processes any remaining audio
   231→    streamingTranscription.commitAudioBuffer();
   232→
   233→    // Wait for final deltas
   234→    setTimeout(async () => {
   235→        streamingTranscription.disconnect();
   236→
   237→        if (currentTranscript.trim()) {
   238→            try {
   239→                // Post-process based on active mode
   240→                const apiKey = settingsManager.getSetting('apiKey');
   241→                const ppSettings = settingsManager.getSetting('postProcessing');
   242→
   243→                const processedText = await textPostProcessor.processWithMode(
   244→                    currentTranscript.trim(),
   245→                    apiKey,
   246→                    mode,
   247→                    ppSettings,
   248→                );
   249→
   250→                // Inject into active app
   251→                await textInjection.injectText(processedText);
   252→
   253→                console.log(`[Main] Injected (${mode}):`, processedText);
   254→
   255→                if (!stealth) {
   256→                    windowManager.sendToRenderer('transcription-complete', {
   257→                        text: processedText,
   258→                    });
   259→                }
   260→            } catch (error: any) {
   261→                console.error('Injection failed:', error);
   262→                if (!stealth) {
   263→                    windowManager.sendToRenderer('recording-error', {
   264→                        message: 'Failed to inject: ' + error.message,
   265→                    });
   266→                }
   267→            }
   268→        }
   269→
   270→        // Restore tray to default
   271→        stopTrayPulse();
   272→
   273→        // Hide overlay
   274→        if (!stealth) {
   275→            setTimeout(() => windowManager.hide(), 600);
   276→        }
   277→
   278→        currentTranscript = '';
   279→    }, 800);
   280→}
   281→
   282→// ─── IPC Handlers ─────────────────────────────────────────
   283→
   284→function setupIPCHandlers() {
   285→    ipcMain.handle('get-settings', () => settingsManager.getSettings());
   286→    ipcMain.handle('update-settings', (_: any, updates: any) => {
   287→        settingsManager.updateSettings(updates);
   288→        // Rebuild tray menu when settings change (mode might change)
   289→        rebuildTrayMenu();
   290→        return { success: true };
