    onTranscriptCompleted: (callback: (data: { text: string; fullText: string; itemId: string }) => void) => {
        ipcRenderer.on('transcript-completed', (_event: IpcRendererEvent, data: { text: string; fullText: string; itemId: string }) => callback(data));
    },
});

