import React from 'react';
import { AudioVisualizer } from './AudioVisualizer';
import { RecordingIndicator } from './RecordingIndicator';
import './OverlayWindow.css';

interface OverlayWindowProps {
    state: 'idle' | 'listening' | 'processing' | 'error';
    mode: 'push-to-talk' | 'toggle';
    audioData: Uint8Array;
    duration: number;
    errorMessage: string;
    isVisible: boolean;
    liveTranscript: string;
    finalTranscript: string;
}

/**
 * Main overlay window container with futuristic glassmorphism design
 */
export function OverlayWindow({
    state,
    mode,
    audioData,
    duration,
    errorMessage,
    isVisible,
    liveTranscript,
    finalTranscript,
}: OverlayWindowProps) {
    const displayText = liveTranscript || finalTranscript;
    const showTranscript = displayText && (state === 'listening' || state === 'processing');

    return (
        <div className={`overlay-container ${isVisible ? 'visible' : 'hidden'} no-select`}>
            <div className={`overlay-window ${state}`}>
                {/* Glow effect container */}
                <div className="glow-ring" />

                {/* Main content */}
                <div className="overlay-content">
                    {/* Audio Visualizer */}
                    <AudioVisualizer audioData={audioData} state={state} />

                    {/* Recording Indicator */}
                    <RecordingIndicator
                        mode={mode}
                        state={state}
                        duration={duration}
                        errorMessage={errorMessage}
                    />

                    {/* Live Transcript Preview */}
                    {showTranscript && (
                        <div className="transcript-preview">
                            <div className="transcript-text">
                                {finalTranscript && (
                                    <span className="transcript-final">{finalTranscript} </span>
                                )}
                                {liveTranscript && (
                                    <span className="transcript-live">{liveTranscript}</span>
                                )}
                                <span className="transcript-cursor">|</span>
                            </div>
                        </div>
                    )}
                </div>

                {/* Accent border */}
                <div className="accent-border" />
            </div>
        </div>
    );
}

