import { useState, useEffect, useRef } from 'react';
import { audioCapture } from '../audioCapture';

/**
 * Hook to get audio visualization data directly from local AudioCapture
 */
export function useAudioVisualization(isRecording: boolean) {
    const [audioData, setAudioData] = useState<Uint8Array>(new Uint8Array(128));
    const animationFrameRef = useRef<number>();

    useEffect(() => {
        if (!isRecording) {
            setAudioData(new Uint8Array(128));
            if (animationFrameRef.current) {
                cancelAnimationFrame(animationFrameRef.current);
            }
            return;
        }

        const updateAudioData = () => {
            const data = audioCapture.getVisualizationData();
            // Create a copy to trigger React re-render
            setAudioData(new Uint8Array(data));
            animationFrameRef.current = requestAnimationFrame(updateAudioData);
        };

        updateAudioData();

        return () => {
            if (animationFrameRef.current) {
                cancelAnimationFrame(animationFrameRef.current);
            }
        };
    }, [isRecording]);

    return audioData;
}

