import React, { useEffect, useRef } from 'react';

interface AudioVisualizerProps {
    audioData: Uint8Array;
    state: 'idle' | 'listening' | 'processing' | 'error';
}

const W = 228;
const H = 36;
const BARS = 40;
const BAR_W = 3;
const GAP = 2.5;
const TOTAL_W = BARS * (BAR_W + GAP) - GAP;
const START_X = (W - TOTAL_W) / 2;

/**
 * Compact horizontal frequency-bar visualizer for the pill overlay.
 */
export function AudioVisualizer({ audioData, state }: AudioVisualizerProps) {
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const animRef = useRef<number>(0);

    useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas) return;
        canvas.width = W;
        canvas.height = H;

        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        const draw = () => {
            ctx.clearRect(0, 0, W, H);

            if (state === 'listening') {
                // Real-time bars from microphone frequency data
                for (let i = 0; i < BARS; i++) {
                    const idx = Math.floor((i / BARS) * audioData.length);
                    const amp = audioData[idx] / 255;
                    const barH = Math.max(2, amp * (H - 4));
                    const x = START_X + i * (BAR_W + GAP);
                    const y = (H - barH) / 2;
                    ctx.fillStyle = `rgba(0, 217, 255, ${0.3 + amp * 0.7})`;
                    ctx.shadowBlur = amp > 0.25 ? 5 : 0;
                    ctx.shadowColor = '#00d9ff';
                    ctx.fillRect(x, y, BAR_W, barH);
                }
            } else if (state === 'processing') {
                // Gentle animated wave while waiting for transcript
                const t = Date.now() / 700;
                for (let i = 0; i < BARS; i++) {
                    const wave = Math.sin(t + i * 0.38) * 0.5 + 0.5;
                    const barH = 2 + wave * 9;
                    const x = START_X + i * (BAR_W + GAP);
                    const y = (H - barH) / 2;
                    ctx.fillStyle = `rgba(255, 200, 50, ${0.2 + wave * 0.25})`;
                    ctx.shadowBlur = 0;
                    ctx.fillRect(x, y, BAR_W, barH);
                }
                animRef.current = requestAnimationFrame(draw);
            } else {
                // Idle / error: flat minimal line
                ctx.shadowBlur = 0;
                for (let i = 0; i < BARS; i++) {
                    const x = START_X + i * (BAR_W + GAP);
                    ctx.fillStyle = 'rgba(255, 255, 255, 0.1)';
                    ctx.fillRect(x, (H - 2) / 2, BAR_W, 2);
                }
            }
        };

        draw();
        return () => { cancelAnimationFrame(animRef.current); };
    }, [audioData, state]);

    return <canvas ref={canvasRef} style={{ display: 'block' }} />;
}
